//PackageAWSAT002definesanAnalyzerthatchecksfor//hardcodedAMIIDspackageAWSAT002import("go/ast""go/token""regexp""github.com/bflad/tfproviderlint/passes/commentignore""golang.org/x/tools/go/analysis""golang.org/x/tools/go/analysis/passes/inspect""golang.org/x/tools/go/ast/inspector")constDoc=`checkforhardcodedAMIIDsTheAWSAT002analyzerreportshardcodedAMIIDs.AMIIDsareregiondependentandtestswillfailinanyregionorpartitionotherthanwheretheAMIwascreated.`constanalyzerName="AWSAT002"varAnalyzer=&analysis.Analyzer{Name:analyzerName,Doc:Doc,Requires:[]*analysis.Analyzer{commentignore.Analyzer,inspect.Analyzer,},Run:run,}funcrun(pass*analysis.Pass)(interface{},error){ignorer:=pass.ResultOf[commentignore.Analyzer].(*commentignore.Ignorer)inspect:=pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)nodeFilter:=[]ast.Node{(*ast.BasicLit)(nil),}re:=regexp.MustCompile("ami-[0-9a-z]{8,17}")inspect.Preorder(nodeFilter,func(nast.Node){x:=n.(*ast.BasicLit)ifignorer.ShouldIgnore(analyzerName,x){return}ifx.Kind!=token.STRING{return}if!re.MatchString(x.Value){return}pass.Reportf(x.ValuePos,"%s:AMIIDsshouldnotbehardcoded",analyzerName)})returnnil,nil}